const body = ($input.first().json && $input.first().json.body) || {};
const topic = body.topic || 'Как собрать 30 постов за час через ИИ';
const reqBody = JSON.stringify({
  model: 'claude-sonnet-4-5-20250929',
  max_tokens: 1500,
  system: "Ты контент-дизайнер канала «Студия ЧЕ» (ИИ для бизнеса, автор — Денис Видяков, практик). Спроектируй ПРИКЛАДНУЮ карусель из 5 слайдов. Верни СТРОГО JSON без markdown: {\\\"caption\\\": \\\"текст под каруселью от первого лица, 2-3 строки пользы + мягкий вывод, 2-3 хэштега\\\", \\\"slides\\\": [{\\\"kind\\\":\\\"cover\\\",\\\"title\\\":\\\"крючок-заголовок капсом до 40 симв\\\",\\\"line\\\":\\\"обещание одной строкой\\\",\\\"image_brief\\\":\\\"что нарисовать (объект/сцена)\\\"}, {\\\"kind\\\":\\\"point\\\",\\\"n\\\":1,\\\"title\\\":\\\"шаг капсом\\\",\\\"line\\\":\\\"1 строка сути\\\",\\\"image_brief\\\":\\\"иконка\\\"}, {\\\"kind\\\":\\\"point\\\",\\\"n\\\":2,...}, {\\\"kind\\\":\\\"point\\\",\\\"n\\\":3,...}, {\\\"kind\\\":\\\"cta\\\",\\\"title\\\":\\\"вывод капсом\\\",\\\"line\\\":\\\"мягкий призыв\\\",\\\"image_brief\\\":\\\"финальная иллюстрация\\\"}]}. Тексты на русском, коротко, по делу, минимум текста на слайде.",
  messages: [{ role: 'user', content: 'Тема прикладной карусели: ' + topic + '. Спроектируй карусель строго в JSON.' }],
});
return [{ json: { reqBody, topic } }];

const res = $input.first().json;
let txt = '';
if (res.content && Array.isArray(res.content)) { const tb = res.content.find(c=>c.type==='text'); txt = tb && tb.text ? tb.text : ''; }
else if (res.choices) { txt = res.choices[0] && res.choices[0].message ? res.choices[0].message.content : ''; }
txt = txt.replace(/\`\`\`json/gi,'').replace(/\`\`\`/g,'').trim();
let design;
try { design = JSON.parse(txt); } catch(e) { return [{ json: { _error: 'json parse', raw: txt.slice(0,300) } }]; }
const topic = $('Build Design Body').first().json.topic;
return [{ json: { caption: design.caption || '', slides: design.slides || [], topic } }];

const d = $input.first().json;
const H = this.helpers;
const TG = $env.TELEGRAM_BOT_TOKEN, ADMIN = $env.TELEGRAM_CHAT_ID;
const tgMsg = async (text) => { try { await H.httpRequest({ method:'POST', url:'https://api.telegram.org/bot'+TG+'/sendMessage', body:{ chat_id:ADMIN, text }, json:true }); } catch(e){} };
if (d._error) { await tgMsg('⚠️ Карусель: дизайн не распарсился — '+(d.raw||'')); return [{ json:{ ok:false } }]; }
const STYLE = "ЕДИНЫЙ ФИРМЕННЫЙ СТИЛЬ канала «Студия ЧЕ» про ИИ для бизнеса. Современная комикс / поп-арт иллюстрация: жирные чёрные контуры, плоские заливки, halftone-текстура точками, динамичные скоростные линии. СТРОГО ОГРАНИЧЕННАЯ ПАЛИТРА: насыщенный оранжевый #FF6A00, чистый чёрный, белый — никаких других цветов. Типографика: один жирный гротескный шрифт без засечек, заголовки КАПСОМ. Композиция чистая, премиальная, много воздуха, НЕ перегружено деталями. Без водяных знаков.";
function slidePrompt(s){
  if (s.kind==='cover') return 'СЛАЙД-ОБЛОЖКА карусели, вертикальный формат. Крупный заголовок капсом по центру, ТОЧНЫЙ текст без ошибок: «'+(s.title||'')+'». Ниже подзаголовок: «'+(s.line||'')+'». Иллюстрация: '+(s.image_brief||'')+'. Внизу мелко: «СТУДИЯ ЧЕ».';
  if (s.kind==='cta') return 'ФИНАЛЬНЫЙ СЛАЙД карусели, вертикальный. Заголовок капсом: «'+(s.title||'')+'». Строка: «'+(s.line||'')+'». Иллюстрация: '+(s.image_brief||'')+'. Внизу мелко: «СТУДИЯ ЧЕ».';
  return 'СЛАЙД-ПУНКТ карусели, вертикальный. Сверху крупная оранжевая цифра «'+(s.n||'')+'». Заголовок капсом: «'+(s.title||'')+'». Ниже одна строка: «'+(s.line||'')+'». Маленькая комикс-иконка: '+(s.image_brief||'')+'. Минимум текста, много воздуха.';
}
const slides = (d.slides||[]).slice(0,8);
if (!slides.length) { await tgMsg('⚠️ Карусель: пустой список слайдов'); return [{ json:{ ok:false } }]; }
const buffers = [];
for (const s of slides) {
  let j;
  try {
    j = await H.request({ method:'POST', url:'https://api.openai.com/v1/images/generations', headers:{ Authorization:'Bearer '+$env.OPENAI_API_KEY, 'Content-Type':'application/json' }, body:{ model:'gpt-image-2', prompt: STYLE+'\n\n'+slidePrompt(s), size:'1024x1536', n:1 }, json:true, timeout:180000 });
  } catch(e) { await tgMsg('⚠️ Карусель: запрос картинки упал — '+(e.message||e)); throw e; }
  if (!j || !j.data || !j.data[0] || !j.data[0].b64_json) { await tgMsg('⚠️ Карусель: пустой ответ картинки — '+JSON.stringify((j&&j.error)||j).slice(0,200)); throw new Error('img gen'); }
  buffers.push(Buffer.from(j.data[0].b64_json,'base64'));
}
const media = buffers.map((b,i)=>({ type:'photo', media:'attach://f'+i, ...(i===0?{ caption:'🆕 Карусель: '+d.topic }:{}) }));
const formData = { chat_id: String(ADMIN), media: JSON.stringify(media) };
buffers.forEach((b,i)=>{ formData['f'+i] = { value:b, options:{ filename:'s'+i+'.png', contentType:'image/png' } }; });
let sent;
try { sent = await H.request({ method:'POST', url:'https://api.telegram.org/bot'+TG+'/sendMediaGroup', formData }); }
catch(e) { const info = { name:(e&&e.name), statusCode:(e&&e.statusCode), message:(e&&e.message), error: JSON.stringify((e&&e.error)||'').slice(0,200), keys:Object.keys(e||{}).join(',') }; await tgMsg('⚠️ sendMediaGroup ИСКЛЮЧЕНИЕ:\n'+JSON.stringify(info,null,2).slice(0,700)); throw e; }
if (typeof sent === 'string') { try { sent = JSON.parse(sent); } catch(e){} }
if (!sent || !sent.ok) { await tgMsg('⚠️ Карусель: sendMediaGroup ошибка — '+JSON.stringify(sent).slice(0,200)); throw new Error('sendMediaGroup'); }
const fileIds = sent.result.map(m => { const ph = m.photo; return ph[ph.length-1].file_id; });
const id = 'carousel_' + Date.now();
return [{ json: { id, caption: d.caption || '', topic: d.topic, fileIds, count: fileIds.length } }];
